CREATE TABLE IF NOT EXISTS cookie_data(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id UUID NOT NULL REFERENCES tenants(id),user_id UUID REFERENCES users(id),platform_id TEXT NOT NULL,display_name TEXT NOT NULL DEFAULT '',cookie_type TEXT NOT NULL DEFAULT 'folder',encrypted_data BYTEA NOT NULL,encrypted_keys JSONB NOT NULL DEFAULT '{}',status TEXT NOT NULL DEFAULT 'available',used_by_task_id UUID,file_name TEXT NOT NULL DEFAULT '',size_bytes BIGINT NOT NULL DEFAULT 0,created_at TIMESTAMPTZ DEFAULT now(),updated_at TIMESTAMPTZ DEFAULT now());COMMENT ON TABLE cookie_data IS '加密cookie';COMMENT ON COLUMN cookie_data.encrypted_keys IS '{agent_id:加密的SK}';CREATE INDEX IF NOT EXISTS idx_cookie_data_tenant ON cookie_data(tenant_id);ALTER TABLE tenants ADD COLUMN IF NOT EXISTS cookie_sharing_enabled BOOLEAN NOT NULL DEFAULT true;COMMENT ON COLUMN tenants.cookie_sharing_enabled IS '租户cookie共享开关';
